
const { sObserver } = require('@/utils/simpleObserver.js')
import { ref, reactive, onMounted, watch } from 'vue';
import { Popup, RadioGroup, Radio } from 'vant'
import {  getUrlParam1 } from '@/utils/index';

import { wrong_question_deriveset_click } from '../js/sensors'
export default{
  components: {
    'van-popup':Popup,
    'van-radio-group':RadioGroup,
    'van-radio':Radio
  },
  props: ["selForm","forbidScope","typeRes"],
  setup(props:any){
    const show = ref(false)
    const params = reactive({
      scope:1,
      show_answer:true,
      subject_id:0,
      token:''
    })
    const cancel = ()=>{
      clickSensor('取消')
      show.value = false
    }
    const sure = ()=>{
      clickSensor('确定')
      const tal_id = getUrlParam1('tal_id') || ''
      let pdf_name = '错题本'
      let subject = ''
      props.typeRes.subject.map((item:any)=>{
        if(item.id === params.subject_id){
          pdf_name = item.val+'错题本'
          subject = item.val
        }
      })
      const current_id = getUrlParam1('current_id')
      const domain = location.origin
      if(current_id){
        const url = domain+'/mbxpp/#/parentNodePdf?question_ids='+current_id+'&&show_answer='+params.show_answer+'&&scope='+params.scope+'&&tal_id='+tal_id+'&&subject='+subject
        const p = {
          url:url,
          type:1,
          pdf_token:params.token,
          pdf_name:pdf_name,
          source:2,
          tal_id:tal_id,
          source_name:getSourceName()
        }
        console.log('导出传参',p)
        window.ConnectWebViewBridgeSDK.exportPdf(p)
      }else{
        sObserver.fire("getCheckedList",(list:any)=>{
          const question_ids = [].concat(list).splice(0,25).join(',')
          console.log(question_ids)
          const url = domain + '/mbxpp/#/parentNodePdf?question_ids='+question_ids+'&&show_answer='+params.show_answer+'&&scope='+params.scope+'&&tal_id='+tal_id+'&&subject='+subject
          const p = {
            url:url,
            type:1,
            pdf_token:params.token,
            pdf_name:pdf_name,
            source:2,
            tal_id:tal_id,
            source_name:getSourceName()
          }
          console.log('导出传参',p)
          window.ConnectWebViewBridgeSDK.exportPdf(p)
        })
      }
    }
    const showExport = ()=>{
      show.value = true
    }
    const getSourceName = ()=>{
      const current_id = getUrlParam1('current_id')
      const source = getUrlParam1('source')
      let source_name = ''
      if(current_id&&source==='1'){
        source_name = '错题本单题管理'
      }
      if(!current_id&&source==='1'){
        source_name = '错题本多选导出'
      }
      if(current_id&&source==='2'){
        source_name = '学情详情单题管理'
      }
      if(!current_id&&source==='2'){
        source_name = '学情详情多选导出'
      }
      return source_name
    }
    const clickSensor = (type:string)=>{
      const source_name = getSourceName()
      wrong_question_deriveset_click({
        source_name:source_name,
        answer_type:params.show_answer?'附答案解析':'不附答案解析',
        extra_type:params.scope===1?'错题':'举一反三',
        type:type
      })
    }
    watch(
      () => props.selForm.subject_id,
      (newVal, oldVal) => {
        params.subject_id = newVal
      }
    )
    onMounted(async() => {
      const subject_id = Number(getUrlParam1('subject_id'))
      if(subject_id) params.subject_id = subject_id
      sObserver.unWatch('showExport', showExport)
      sObserver.watch('showExport', showExport)

      window.ConnectWebViewBridgeSDK.getToken((token: any) => {
        params.token = token
      });

    })
    return{
      params,
      show,
      cancel,
      sure
    }
  }
}
