
import { ref, reactive,onMounted } from 'vue';
import { DropdownMenu, DropdownItem, Tabbar, TabbarItem} from 'vant'
import { wrong_question_single_click } from '../js/sensors'
import '../css/vantSel.less'
export default{
  components: {
    'van-dropdown-menu':DropdownMenu,
    'van-dropdown-item':DropdownItem,
    'van-tabbar':Tabbar,
    'van-tabbar-item':TabbarItem,
  },
  emits: ['selSearch'],
  props: ["typeRes"],
  setup(props:any, context:any){
    const stateRef = ref()
    const gradeRef = ref()
    const timeRef = ref()
    const sourceRef = ref()
    const info = reactive({
      grade:0,
      source:0,
      time:0,
      status:0,
      gradeTitle:'年级',
      sourceTitle:'来源',
      timeTitle:'时间',
      stateTitle:'状态'
    }) as any
    // 处理选中类型
    const handelSelcted = (id:number,arr:any,type:string,title:string,defName:string)=>{
      for(let i=0;i<arr.length;i++){
        if(arr[i].id === id){
          info[title] = id===0? defName : arr[i].val
          info[type] = arr[i].id
          wrong_question_single_click(info[title])
          break
        } 
      }
      context.emit('selSearch',info)
    }
    const changeGradeSel = (val:number)=>{
      gradeRef.value.toggle();
      handelSelcted(val,props.typeRes.grade,'grade','gradeTitle','年级')
    }
    const changeSourceSel = (val:any)=>{
      sourceRef.value.toggle();
      handelSelcted(val,props.typeRes.source_type,'source','sourceTitle','来源')
    }
    const changeTimeSel = (val:any)=>{
      timeRef.value.toggle();
      handelSelcted(val,props.typeRes.time_range,'time','timeTitle','时间')
    }
    const changeStateSel = (val:any)=>{
      stateRef.value.toggle();
      handelSelcted(val,props.typeRes.status,'status','stateTitle','状态')
    }
    return{
      info,
      stateRef,
      gradeRef,
      timeRef,
      sourceRef,
      changeGradeSel,
      changeSourceSel,
      changeTimeSel,
      changeStateSel
    }
  }
}
