
import { ref, reactive, onMounted } from 'vue';
import { Checkbox,Toast } from 'vant'
const { sObserver } = require('@/utils/simpleObserver.js')
import { wrong_question_derive_click } from '../js/sensors'
import sureDialog from './sureDialog.vue'
export default{
  components: {
    'Checkbox':Checkbox,
    sureDialog
  },
  setup(){
    const checked = ref(false)
    const isChecked = ref(false)
    const checkedNum = ref(0)
    const sureLimitDialogRef = ref()
    const sureInfo = reactive({
      title:'确认导出',
      desc:'单次导出题目数量超出上限，超出部分无法导出',
      cancelBtn:'取消',
      sureBtn:'确定'
    })
    const checkedChange = (val:boolean)=>{
      isChecked.value = checked.value
      sObserver.fire("checkedAll",checked.value)
      setTimeout(()=>{
        sObserver.fire("getCheckedList",(list:any)=>{
          checkedNum.value = list.length
          if(list.length>25) Toast('选中题目数量已超上限')
        })
      })
      wrong_question_derive_click('全选')
    }
    const exportPdf = ()=>{
      if(isChecked.value){
        if(checkedNum.value>25){
          sureLimitDialogRef.value.showPop(true)
        }else{
          wrong_question_derive_click('导出')
          sObserver.fire("showExport")
        }
      }
    }
    const getChecked = (params:any)=>{
        const myChecked = params.checked
        checkedNum.value = myChecked.length
        if(myChecked.length>25) Toast('选中题目数量已超上限')
        if(myChecked.length>0){
          isChecked.value = true
        }else{
          isChecked.value = false
        }
        const questionRealList = params.questionRealList
        if(myChecked.length!==questionRealList.length){
          checked.value = false
        }else{
          checked.value = true
        }
    }
    const sureBtn = ()=>{
      if(isChecked.value){
        sObserver.fire("showExport")
      }
    }
    const cancelBtn = ()=>{
      console.log('取消')
    }
    onMounted(async() => {
      // 获取选中的数据
      sObserver.unWatch('getChecked', getChecked)
      sObserver.watch('getChecked', getChecked)
    })
    return{
      checked,
      isChecked,
      checkedChange,
      exportPdf,
      checkedNum,
      sureBtn,
      cancelBtn,
      sureLimitDialogRef,
      sureInfo
    }
  }
}
