
import { ref, reactive, onMounted, watch } from 'vue';
import selHead from './components/selHead.vue'
import selectSearch from './components/selectSearch.vue'
import errorList from './components/errorList.vue'
import checkedAll from './components/checkedAll.vue'
import exportPdf from './components/exportPdf.vue'
import { getUrlParam1 } from '@/utils/index';
import api from './service/api'
import router from '@/router';
const { sObserver } = require('@/utils/simpleObserver.js')
export default{
  components: {
    selHead,
    selectSearch,
    errorList,
    checkedAll,
    exportPdf
  },
  setup(){
    const switch1 = ref(false);
    const value = ref(0);
    // 根据导出取消是否显示菜单和底部
    const showSel = ref(true)
    // false表示从错题进入
    const showSelFlag = ref(true)
    const hasTags = ref(false)
    const selForm = reactive({
      subject_id:0,
      grade_id:0,
      source_type:0,
      time_range:0,
      status:0,
      tal_id:'',
      myTitle:''
    })
    const typeRes: any = ref({})
    // 配置列表
    const getConfig = async ()=>{
      const token = getUrlParam1('token') || ''
      const res:any = await api.getBookConfig({ token: decodeURIComponent(token)})
      if (res.data.errcode === 0 && Object.prototype.toString.call(res.data.data)==='[object Object]') {
        typeRes.value = res.data.data
      }
    }
    const selSubject = (val:number)=>{
      selForm.subject_id = val
    }
    const selSearch = (val:any)=>{
      selForm.grade_id = val.grade
      selForm.source_type = val.source
      selForm.time_range = val.time
      selForm.status = val.status
    }
    const exportData1 = (val:boolean)=>{
      showSel.value = !val
    }
    const goback = ()=>{
      window.ConnectWebViewBridgeSDK.goback()
    }
    watch(
      () => selForm.subject_id,
      (newVal, oldVal) => {
        if(newVal===2) {
          hasTags.value = true
        }else{
          hasTags.value = false
        }
      }
    )
    onMounted(async() => {
      // 表示从错题进入
      if(getUrlParam1('source') === '2') {
        showSelFlag.value = false
        selForm.myTitle = '错题'
      }
      const subject_id = getUrlParam1('subject_id')
      if(subject_id==='2') hasTags.value = true
      await getConfig()
      sObserver.unWatch('exportData', exportData1)
      sObserver.watch('exportData', exportData1)
    })
    return{
      switch1,
      value,
      hasTags,
      showSel,
      showSelFlag,
      selSubject,
      selSearch,
      typeRes,
      selForm,
      goback
    }
  }
}
