
import { ref, reactive, onMounted, watch } from 'vue';
import { List, Checkbox, CheckboxGroup, Loading, PullRefresh } from 'vant'
import { getUrlParam1, parseTime, getUrlAllParamsObj, getVersion, compareVersion } from '@/utils/index';
import question from './question.vue'
import api from '../service/api'
const { sObserver } = require('@/utils/simpleObserver.js')
import { wrong_question_single_click, wrong_question_derive_click } from '../js/sensors'


export default{
  components: {
    'List':List,
    'Checkbox':Checkbox,
    'CheckboxGroup':CheckboxGroup,
    'van-pull-refresh':PullRefresh,
    'van-loading':Loading,
    question
  },
  props: ["typeRes","selForm"],
  setup(props:any){
    const myForm = reactive({
      loading:false,
      finished:false,
      showExport:false,
      refreshing:false,
      showLoading:false,
      pageNo:25,
      limit:25,
      page:1,
      subject_id:0,
      grade_id:'',
      source_type:0,
      time_range:0,
      status:0,
      plan_ids:'',
      checked:[]
    })
    const questionList = ref([]) as any
    // 真实问题数量
    const questionRealList = ref([]) as any
    const checkboxGroup = ref()
    const noData = ref(false)
    const showSelFlag = ref(true)
    const source = ref('1')
    // 解码数据
    const unzip = (b64Data:any)=> {
      var decodedData = window.atob(b64Data);
      var data = window.pako.ungzip(decodedData, { to: "string" });
      return data
    }
    // 错题列表 isFresh是否刷新触发 则清空数据
    const getBookList = async (isFresh:boolean)=>{
      myForm.showLoading = true
      const token = getUrlParam1('token') || ''
      const tal_id = getUrlParam1('tal_id')
      const date = getUrlParam1('date')||''
      try{
        const res = await api.getBookList({ 
          token: decodeURIComponent(token), 
          subject_id:myForm.subject_id, 
          grade_id:myForm.grade_id,
          source_type:myForm.source_type,
          time_range:myForm.time_range,
          status:myForm.status,
          page: myForm.page,
          tal_id:tal_id,
          date:date,
          page_size: myForm.pageNo,
          plan_ids:myForm.plan_ids,
        })
        if(isFresh){
          questionList.value.length = 0
          questionRealList.value.length = 0
        }
        myForm.loading = false
        myForm.refreshing = false
        myForm.showLoading = false
        if (res.data.errcode === 0 && res.data.data) {
          res.data.data = JSON.parse(unzip(res.data.data))
          handelErrorList(res.data.data)
          if(questionRealList.value.length===0){
            noData.value = true
          }else{
            noData.value = false
          }
        }
        sObserver.fire("getListLen",questionRealList.value.length)
      }catch(e){
        myForm.loading = false
        myForm.refreshing = false
        myForm.showLoading = false
        // questionList.value = []
        // questionRealList.value = []
        if(questionRealList.value.length===0){
          noData.value = true
        }else{
          noData.value = false
        }
      }
    }
    function getUuid(randomLength: number){
      return Number(Math.random().toString().substr(2,randomLength) + Date.now()).toString(36)
    }
    // 处理列表
    const handelErrorList = (data:any)=>{
      const list = data.list
      const day_question_count = data.day_question_count
      const plan_question_count = data.plan_question_count
      let lastDay = ''
      let lastPlan = ''
      // 走学习详情处理逻辑
      if(myForm.plan_ids){
        list.map((item:any)=>{
          // 第一个放标题
          if(lastPlan !== item.plan_name){
            const titleObj = {plan_name:item.plan_name,count:plan_question_count[item.plan_name],isTitle:true, id:getUuid(36)}
            lastPlan = item.plan_name
            questionList.value.push(titleObj)
          }
          questionList.value.push(item)
          questionRealList.value.push(item)
        })
      }else{
        list.map((item:any)=>{
          // 第一个放标题
          if(lastDay !== item.date){
            // 上一次列表还是当前日期就添加标头
            const myitem = questionRealList.value[questionRealList.value.length-1]
            if(questionRealList.value.length===0||myitem&&myitem.date!==item.date){
              const today = parseTime(new Date(),'{y}-{m}-{d}')
              const yesterday = parseTime(new Date().getTime()-24*60*60*1000,'{y}-{m}-{d}')
              let day = parseTime(item.date,'{m}月{d}日')
              if(day.substr(0,1) === '0') day = day.substr(1)
              if(item.date === today) day = '今天'
              if(item.date === yesterday) day = '昨天'
              if(new Date().getFullYear()>new Date(item.date).getFullYear()){
                day = parseTime(item.date,'{y}年{m}月{d}日')
              }
              const titleObj = {date:day,count:day_question_count[item.date],isTitle:true, id:getUuid(36)}
              lastDay = item.date
              questionList.value.push(titleObj)
            }
          }
          questionList.value.push(item)
          questionRealList.value.push(item)
        })
      }
      if(list.length === myForm.pageNo){
        myForm.page ++
      }else{
        myForm.finished = true
      }
    }
    const onRefresh = ()=>{
      myForm.finished = false
      myForm.loading = true
      myForm.page = 1
      initScrollTop()
      getBookList(true)
    }
    const checkboxgroupChange = ()=>{
      wrong_question_derive_click('单选')
      sObserver.fire("getChecked",{checked:myForm.checked,questionRealList:questionRealList.value})
    }
    const jumpWrongQuesDetail = async (info:any)=>{
      if(myForm.showExport) return
      const token = getUrlParam1('token') || ''
      const tal_id = getUrlParam1('tal_id')
      wrong_question_single_click('单题卡片')
      const domain = location.origin

      // 修改当前url上的subject_id，fix从详情页删除之后返回列表页科目不对的问题
      const curUrlParams = getUrlAllParamsObj()
      curUrlParams.subject_id = myForm.subject_id
      const shouldUrl = window.location.href.split('?')[0] + '?' + Object.keys(curUrlParams).reduce((acc: string, cur: any)=> {
        return acc + cur + '=' + curUrlParams[cur] + '&'
      }, '').slice(0, -1)

      // 判断一下版本，旧版本中刷新webview,匹配的是webview第一个打开页面的url，旧版本保持一致，在详情删除之后返回列表也可以完成刷新
      // 新版本跳转走详情会改变webview的h5的url，在详情页调用refreshUrl 可以刷新当前webview的最新的url 对应的前端页面
      const { version } = await getVersion()
      const isUseNewUrl = (compareVersion(version, '1.24.0') >= 0)

      const url = domain+'/mbxpp/#/parentBookDetail?subject_id='+myForm.subject_id+'&tal_id='+tal_id+'&source='+source.value+'&date='+info.date+'&grade_id='+myForm.grade_id+'&current_id='+info.id+'&source_type='+info.source_type+'&plan_id='+info.plan_id+'&token='+decodeURIComponent(token)+'&statusBarBgColor=FFFFFF'+'&appbar=hide'+'&beforeUrl='+encodeURIComponent(isUseNewUrl ? shouldUrl : window.location.href)
      console.log(url)
      window.ConnectWebViewBridgeSDK.jumpToH5Handler({ url: url, title: '错题详情' })
      isUseNewUrl && window.location.replace(shouldUrl)
    }
    const onLoad = ()=>{
      myForm.loading = true
      getBookList(false)
      console.log('onLoad')
    }
    const initScrollTop = ()=>{
      const taldom = document.getElementsByClassName("error-list")
      taldom[0].scrollTop = 0
    }
    const initWatch = ()=>{
      myForm.page = 1
      myForm.loading = true
      myForm.finished = false
      initScrollTop()
      getBookList(true)
    }
    watch(
      () => props.selForm.subject_id,
      (newVal, oldVal) => {
        myForm.subject_id = newVal
        initWatch()
      }
    )
    watch(
      () => props.selForm.grade_id,
      (newVal, oldVal) => {
        myForm.grade_id = newVal.toString()
        initWatch()
      }
    )
    watch(
      () => props.selForm.source_type,
      (newVal, oldVal) => {
        myForm.source_type = newVal
        initWatch()
      }
    )
    watch(
      () => props.selForm.time_range,
      (newVal, oldVal) => {
        myForm.time_range = newVal
        initWatch()
      }
    )
    watch(
      () => props.selForm.status,
      (newVal, oldVal) => {
        myForm.status = newVal
        initWatch()
      }
    )
    watch(
      ()=>questionRealList,
      (newVal, oldVal)=>{
        if(myForm.showExport){
          sObserver.fire("getChecked",{checked:myForm.checked,questionRealList:questionRealList.value})
        }
        },{deep:true}
    )
    const exportData2 = (val:boolean) => {
      myForm.showExport = val
      if(!val){
        myForm.checked = []
      }
    }
    const checkedAll = (val:boolean) => {
      checkboxGroup.value.toggleAll(val);
    }
    const getCheckedList = (callback:any) => {
      callback(myForm.checked)
    }
    const handelSourceType = (id:number)=>{
      let name = ''
      props.typeRes.source_type.map((item:any)=>{
        if(item.id === id){
          name = item.val
        }
      })
      return name
    }
    onMounted(() => {
      const subject_id = Number(getUrlParam1('subject_id'))
      const plan_ids = getUrlParam1('plan_ids')
      if(subject_id) myForm.subject_id = subject_id
      if(plan_ids) {
        myForm.plan_ids = plan_ids
        showSelFlag.value = false
      }
      source.value = getUrlParam1('source') || ''
      getBookList(false)
      // 导出、取消
      sObserver.unWatch('exportData', exportData2)
      sObserver.watch('exportData', exportData2)
      // 全选、取消
      sObserver.unWatch('checkedAll', checkedAll)
      sObserver.watch('checkedAll', checkedAll)
      // 获取选中
      sObserver.unWatch('getCheckedList', getCheckedList)
      sObserver.watch('getCheckedList', getCheckedList)
    })
    return{
      myForm,
      questionList,
      source,
      checkboxGroup,
      checkboxgroupChange,
      jumpWrongQuesDetail,
      onLoad,
      onRefresh,
      noData,
      showSelFlag,
      handelSourceType
    }
  }
}
