
import { ref, reactive } from 'vue';
import { Popup } from 'vant'
import '../css/vantSel.less'
export default{
  components: {
    'van-popup':Popup
  },
  props: ['sureInfo'],
  setup(props:any, context:any){
    const info = reactive({
      showPop:false
    })
    const showPop = (val:boolean)=>{
      info.showPop = val
    }
    const cancelBtn = ()=>{
      showPop(false)
      context.emit('cancelBtn')
    }
    const sureBtn = ()=>{
      showPop(false)
      context.emit('sureBtn')
    }
    return{
      info,
      showPop,
      sureBtn,
      cancelBtn
    }
  }
}
