import ApiService, { ResponseType } from '@/api/api';
import { getTokenByBridge } from '@/utils';

export default {
  async getBookList(obj: any): ResponseType<string> {
    const token = await getTokenByBridge();
    return ApiService.post('/parent/api/v2/error-book/list', { ...obj, token });
  },
  async getBookConfig(obj: any): ResponseType<string> {
    const token = await getTokenByBridge();
    return ApiService.post('/parent/api/v1/error-book/config', { ...obj, token });
  },
  async getBookDetail(obj: any): ResponseType<string> {
    const token = await getTokenByBridge();
    return ApiService.post('/parent/api/v1/error-book/detail', { ...obj, token });
  }
};
