
import { ref, reactive, onMounted, watch } from 'vue';
import { DropdownMenu, DropdownItem, Tabbar, TabbarItem } from 'vant';
import { getUrlParam1 } from '@/utils/index';
import {
  wrong_question_single_click,
  wrong_question_derive_click
} from '../js/sensors';
const { sObserver } = require('@/utils/simpleObserver.js');
import '../css/vantSel.less';
export default {
  components: {
    'van-dropdown-menu': DropdownMenu,
    'van-dropdown-item': DropdownItem,
    'van-tabbar': Tabbar,
    'van-tabbar-item': TabbarItem
  },
  emits: ['selSubject', 'delData', 'goback'],
  props: ['typeRes', 'myTitle', 'isDel', 'countInfo'],
  setup(props: any, context: any) {
    const info = reactive({
      subject: 0,
      title: '',
      listLen: 0
    });
    const selHeadRef = ref();
    const showExport = ref(true);
    const changeSubjectSel = (id: number) => {
      selHeadRef.value.toggle();
      handelSubject(id);
      context.emit('selSubject', id);
    };
    // 处理选中学科
    const handelSubject = (id: number) => {
      for (let i = 0; i < props.typeRes.subject.length; i++) {
        if (props.typeRes.subject[i].id === id) {
          info.title = props.typeRes.subject[i].val;
          info.subject = props.typeRes.subject[i].id;
          break;
        }
      }
    };
    const exportData = (flag: boolean) => {
      if (flag) wrong_question_single_click('导出');
      if (!flag) wrong_question_derive_click('取消');
      showExport.value = !flag;
      sObserver.fire('exportData', flag);
    };
    const goback = () => {
      wrong_question_single_click('返回');
      context.emit('goback');
    };
    const delData = () => {
      wrong_question_single_click('删除');
      context.emit('delData');
    };
    const getListLen = (len: number) => {
      info.listLen = len;
    };
    watch(
      () => props.typeRes,
      (newVal, oldVal) => {
        const subject_id = Number(getUrlParam1('subject_id'));
        if (subject_id) handelSubject(subject_id);
      }
    );
    onMounted(() => {
      sObserver.unWatch('getListLen', getListLen);
      sObserver.watch('getListLen', getListLen);
    });
    return {
      info,
      selHeadRef,
      changeSubjectSel,
      exportData,
      showExport,
      goback,
      delData
    };
  }
};
